// Drives the cursor-following blob mask on .box-overlay-gray elements.
// Updates per-element --blob-x / --blob-y CSS vars so the grayscale layer's
// radial-gradient mask reveals original colors under the cursor.
(function () {
	"use strict";

	function bind(box) {
		if (box.dataset.blobBound === "1") return;
		box.dataset.blobBound = "1";

		var inside = false;
		var rect = null;

		function update(e) {
			if (!inside) return;
			rect = rect || box.getBoundingClientRect();
			var x = ((e.clientX - rect.left) / rect.width) * 100;
			var y = ((e.clientY - rect.top) / rect.height) * 100;
			box.style.setProperty("--blob-x", x + "%");
			box.style.setProperty("--blob-y", y + "%");
		}

		box.addEventListener("pointerenter", function () {
			inside = true;
			rect = box.getBoundingClientRect();
		});
		box.addEventListener("pointermove", update);
		box.addEventListener("pointerleave", function () {
			inside = false;
			// Park blob off-canvas so the whole box returns to gray.
			box.style.setProperty("--blob-x", "-200%");
			box.style.setProperty("--blob-y", "-200%");
		});

		// Recompute rect on scroll/resize while hovering.
		window.addEventListener("resize", function () {
			rect = box.getBoundingClientRect();
		});
	}

	function scan() {
		document.querySelectorAll(".box-overlay-gray").forEach(bind);
	}

	if (document.readyState !== "loading") scan();
	else document.addEventListener("DOMContentLoaded", scan);
	window.addEventListener("load", scan);
	new MutationObserver(scan).observe(document.body, {
		childList: true,
		subtree: true,
	});
})();
